#include<bits/stdc++.h>
using namespace std;
const int N=100005;
vector<pair<int,int> > g[N];
int n,m,dis[N];
void dfs(int num,int f,int xorr)
{
    dis[num]=xorr;
    for(int i=0;i<g[num].size();i++)
    {
        if(g[num][i].first!=f) dfs(g[num][i].first,num,xorr^g[num][i].second);
    }
}
int main()
{

    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        cin>>u>>v>>w;
        g[u].push_back(make_pair(v,w));
        g[v].push_back(make_pair(u,w));
    }
    dfs(1,1,1);
    cin>>m;
    while(m--)
    {
        int u,v;
        cin>>u>>v;
        cout<<(dis[u]^dis[v])<<'\n';
    }
    return 0;
}
